t.script:
//
document.addEventListener('DOMContentLoaded', function() {
    // Get today's date in YYYY-MM-DD format
    const today = new Date().toISOString().split('T')[0];

    // Set minimum date for all inputs with 'future-date-input' class
    document.querySelectorAll('.future-date-input').forEach(input => {
        input.setAttribute('min', today);
        // Also set default value to today for convenience
        if(!input.value) input.value = today;
    });

    // Form submission validation
    document.querySelectorAll('.date-validation-form').forEach(form => {
        form.addEventListener('submit', function(e) {
            const dateInputs = this.querySelectorAll('.future-date-input');
            let isValid = true;

            dateInputs.forEach(input => {
                if (input.value < today) {
                    isValid = false;
                    input.classList.add('is-invalid');
                } else {
                    input.classList.remove('is-invalid');
                }
            });

            if (!isValid) {
                e.preventDefault();
                alert("Invalid Date Selection: Please select today's date or a future date. Past dates are not allowed for borrowing or reservations.");
            }
        });
    });

    // Rating Star Logic (already existed)
    document.querySelectorAll('.rating-star').forEach(star => {
        star.addEventListener('click', function() {
            let val = parseInt(this.getAttribute('data-val'));
            let parent = this.closest('.d-flex');
            parent.querySelectorAll('.rating-star').forEach(s => {
                let sVal = parseInt(s.getAttribute('data-val'));
                s.style.color = sVal <= val ? '#f59e0b' : '#ddd';
            });
            let radio = parent.querySelector('input[value="' + val + '"]');
            if(radio) radio.checked = true;
        });
    });
});
//


function showBookingConfirm() {
    var form = document.getElementById('spaceBookingForm');
    if (!form.checkValidity()) { form.reportValidity(); return; }
    var date = document.getElementById('bookDate').value;
    var startVal = parseFloat(document.getElementById('bookStart').value);
    var endVal   = parseFloat(document.getElementById('bookEnd').value);
    function toTime(v) {
        var h = Math.floor(v), m = Math.round((v - h) * 60);
        return (h < 10 ? '0' : '') + h + ':' + (m < 10 ? '0' : '') + m;
    }
    var heading = document.querySelector('.page-header-vvip h2');
    var spaceName = heading ? heading.textContent.split('—')[0].trim() : '—';
    document.getElementById('popupSpaceName').textContent = spaceName;
    document.getElementById('popupDate').textContent = date;
    document.getElementById('popupTime').textContent = toTime(startVal) + ' – ' + toTime(endVal);
    var overlay = document.getElementById('bookingOverlay');
    var popup   = document.getElementById('bookingPopup');
    overlay.style.display = 'block'; popup.style.display = 'block';
    setTimeout(function() {
        overlay.style.opacity = '1'; popup.style.opacity = '1';
        popup.style.transform = 'translate(-50%, -50%) scale(1)';
    }, 10);
}
function closeBookingPopup() {
    var overlay = document.getElementById('bookingOverlay');
    var popup   = document.getElementById('bookingPopup');
    overlay.style.opacity = '0'; popup.style.opacity = '0';
    popup.style.transform = 'translate(-50%, -50%) scale(0.92)';
    setTimeout(function() { overlay.style.display = 'none'; popup.style.display = 'none'; }, 250);
}
function submitBooking() { document.getElementById('spaceBookingForm').submit(); }

//
    var _cancelFormId = null;
    function showCancelConfirm(bookingId, spaceName, bookingDate) {
        _cancelFormId = 'cancelForm_' + bookingId;
        document.getElementById('cancelPopupSpace').textContent = spaceName || '—';
        document.getElementById('cancelPopupDate').textContent  = bookingDate || '—';
        var overlay = document.getElementById('cancelOverlay');
        var popup   = document.getElementById('cancelPopup');
        overlay.style.display = 'block'; popup.style.display = 'block';
        setTimeout(function() {
            overlay.style.opacity = '1'; popup.style.opacity = '1';
            popup.style.transform = 'translate(-50%, -50%) scale(1)';
        }, 10);
    }
    function closeCancelPopup() {
        var overlay = document.getElementById('cancelOverlay');
        var popup   = document.getElementById('cancelPopup');
        overlay.style.opacity = '0'; popup.style.opacity = '0';
        popup.style.transform = 'translate(-50%, -50%) scale(0.92)';
        setTimeout(function() { overlay.style.display = 'none'; popup.style.display = 'none'; _cancelFormId = null; }, 300);
    }
    function submitCancel() { if (_cancelFormId) { document.getElementById(_cancelFormId).submit(); } }
//
